"""Types for the dependency graph."""

from __future__ import annotations

from dataclasses import dataclass

# Auto-generated declaration suffixes — used to identify Lean-generated
# boilerplate (constructors, recursors, simp lemmas, etc.)
AUTO_GENERATED_SUFFIXES = (
    ".mk",
    ".mk.inj",
    ".rec",
    ".recOn",
    ".casesOn",
    ".noConfusion",
    ".noConfusionType",
    ".brecOn",
    ".below",
    ".ibelow",
    ".binductionOn",
    ".injEq",
    ".sizeOf_spec",
    ".ctorIdx",
    ".match_1",
    ".match_2",
)


@dataclass(frozen=True)
class GraphNode:
    """A single declaration in the dependency graph."""

    name: str
    kind: str  # theorem, def, axiom, inductive, constructor, recursor, opaque, quot
    is_class: bool = False
    is_auto_generated: bool = False  # auto-generated by Lean (e.g. .mk, .rec, .sizeOf_spec)
    has_sorry: bool = False  # body contains sorryAx
    is_unproved: bool = False  # marked with @[unproved] (book does not provide a proof)
    instance_count: int = 0  # for classes: how many project instances exist
    type_head: str = ""  # head constant of the type's conclusion
    deps: tuple[str, ...] = ()  # direct project dependencies
    field_deps: tuple[str, ...] = ()  # subset of deps that are field projections
    tags: tuple[str, ...] = ()  # structural red flags
    all_deps: tuple[str, ...] = ()  # transitive closure
    transitive_axioms: tuple[str, ...] = ()  # project axiom names in transitive chain (+ sorryAx if sorry)
    cone_alerts: tuple[str, ...] = ()  # precomputed alerts derived from support cone


@dataclass(frozen=True)
class SupportCone:
    """The transitive support cone for a target declaration."""

    target: str
    nodes: dict[str, GraphNode]  # all nodes in the cone (keyed by name)
    alerts: tuple[str, ...] = ()  # derived target-level alerts
    flagged_nodes: tuple[str, ...] = ()  # names of nodes with tags
    summary: str = ""  # human-readable summary for LLM judge context
